// src/components/article/TableManager.jsx
import React from 'react';

const TableManager = ({ isOpen, onClose, onSave, editingBlock, tableCounter }) => {
  if (!isOpen) return null;
  
  return (
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      backgroundColor: 'rgba(0,0,0,0.5)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 1000
    }}>
      <div style={{
        backgroundColor: 'white',
        padding: '20px',
        borderRadius: '10px',
        width: '400px'
      }}>
        <h3>Создание таблицы</h3>
        <button onClick={() => {
          onSave({
            caption: 'Тестовая таблица',
            data: [['Ячейка 1', 'Ячейка 2'], ['Ячейка 3', 'Ячейка 4']],
            headers: ['Заголовок 1', 'Заголовок 2']
          });
          onClose();
        }}>
          Создать тестовую таблицу
        </button>
        <button onClick={onClose}>Отмена</button>
      </div>
    </div>
  );
};

export default TableManager;
